code_before_change:
function sanitize_plural_expression($expr) {
  // Get rid of disallowed characters.
  $expr = preg_replace('@[^a-zA-Z0-9_:;\(\)\?\|\&=!<>+*/\%-]@', '', $expr);

  // Add parenthesis for tertiary '?' operator.
  $expr .= ';';
  $res = '';
  $p = 0;
  for ($i = 0; $i < strlen($expr); $i++) {
    $ch = $expr[$i];
    switch ($ch) {
    case '?':
      $res .= ' ? (';
      $p++;
      break;
    case ':':
      $res .= ') : (';
      break;
    case ';':
      $res .= str_repeat( ')', $p) . ';';
      $p = 0;
      break;
    default:
      $res .= $ch;
    }
  }
  return $res;
}

