	if(preg_match('#\$config\[(([\'|"]database[\'|"])|([^\'"].*?))\]\[(([\'|"](database|hostname|password|table_prefix|username)[\'|"])|([^\'"].*?))\]#i', $template)) 
	{
		return true;
	}

	// System calls via backtick
	if(preg_match('#\$\s*\{#', $template))
